var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"저번 촬영도 그렇고, 또 저희가 폐를 끼쳤네요.","JPN":"前回の撮影の件もですが、またご迷惑をおかけしましたね。","ENG":"I'm terribly sorry about what happened. Especially after our previous visit...","TWN":"上次的拍攝也是，我們又給您添麻煩了。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"보호자로서 대신 사과드립니다.","JPN":"保護者として、この子に代わってお詫びします。","ENG":"Please allow me to apologize on her behalf as her guardian.","TWN":"作為監護人，我替她向您道歉。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하하, 괜찮습니다. 작은 해프닝이었는데요.","JPN":"はは、大丈夫ですよ。ちょっとしたハプニングでしたから。","ENG":"Hah hah, no worries. It was just a little hiccup, that's all.","TWN":"哈哈，沒關係，小小的事故而已。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"가은 양 상태는 좀 어떻습니까. 그날 이후로 통 방송에 안 나온다던데.","JPN":"ユキさんの調子はどうですか？　あの日以来、放送にも出てないと聞きましたが。","ENG":"How is Gaeun doing? I haven't seen her on the show ever since then.","TWN":"嘉恩小姐好一點了嗎？聽說從那之後就沒再上直播了。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"의사 얘기로는 몸살이라네요. 뭐, 카운터라고 늘 컨디션이 좋으란 법은 없으니까요.","JPN":"医師の話だと、疲れが溜まっているようです。\\nまあ、カウンターだからって常に調子がいいわけではありませんから。","ENG":"The doctor says she's just suffering from fatigue. Counters aren't immune to exhaustion, after all.","TWN":"醫生說是疲勞所致。畢竟制裁者也會有狀況不好的時候。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"문제는 몸이 아니라 마음이에요.","JPN":"ですが問題は体ではなく、心のほうです。","ENG":"It's not her body I'm worried about though.","TWN":"問題不在於身體，而是心理上。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"자기가 왜 그런 짓을 한 건지도 기억 못하는 상태인데......","JPN":"自分がどうしてそんなことをしたのかさえ覚えていない状態なのに……","ENG":"She doesn't seem to remember why she did those things...","TWN":"儘管她連自己為什麼會那樣做，都不記得了……"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"뭔가 상심이 큰 것 같더라고요.","JPN":"かなり落ち込んでいるみたいなんです。","ENG":"But she seems very broken-hearted for some reason.","TWN":"但似乎有什麼令她心碎的事情。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"혹시 짚이는 곳 없으세요?","JPN":"何か心当たりはありませんか？","ENG":"Would you happen to have any guesses as to why?","TWN":"您有什麼頭緒嗎？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"도움이 되지 못해서 죄송합니다. 저도 쓰러진 가은 양을 발견한 것뿐이라.","JPN":"力になれなくてすみません。私も倒れたユキさんを見つけただけですから。","ENG":"Sorry I can't be of much help with that. She was already passed out when I found her.","TWN":"很抱歉我無法幫上忙，我也只是發現了暈過去的嘉恩小姐而已。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"아, 병원에 다 왔군요. 이만 끊겠습니다.","JPN":"あ、病院に着きましたね。もう切ります。","ENG":"Oh, I've reached the hospital now. I'll hang up now. Take care.","TWN":"啊，已經到醫院了，那麼我就先掛了。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"가은 양. 몸은 좀 어떤가?","JPN":"ユキさん。体の調子はどうだ？","ENG":"Gaeun. How are you feeling?","TWN":"嘉恩小姐。身體怎麼樣了？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"누구......? 선생...... 님......?","JPN":"誰……？　先……生……？","ENG":"Who... are you? Teacher... Is it you?","TWN":"誰……老……老師……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"이거...... 꿈은 아니겠죠?","JPN":"これ……夢じゃないですよね？","ENG":"This... isn't a dream, is it?","TWN":"這……這不是夢吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"아니, 꿈이 맞단다.","JPN":"いや、夢だよ。","ENG":"Actually, it is a dream.","TWN":"不，這是夢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"누구나 행복한 꿈을 꾸는 시간이 필요하니까.","JPN":"誰だって幸せな夢を見る時間は必要だから。","ENG":"Everyone deserves to have a happy dream every now and then.","TWN":"畢竟每個人都得有段時間，來做場幸福的夢"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......죄송해요. 선생님. 폐를 끼쳐 버렸어요.","JPN":"……ごめんなさい、先生。迷惑をかけてしまいましたね。","ENG":"I'm sorry... Teacher. I've made a fool of myself.","TWN":"……非常抱歉，老師，給您添麻煩了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};